module sr_latch (  
    input wire SR_S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (SR_S or R) begin  
        if (SR_S && !R) begin  
            Q = 1;  
            Qn = 0;  
        end  
        else if (!SR_S && R) begin  
            Q = 0;  
            Qn = 1;  
        end  
        // if both SR_S and R are low, hold the previous state  
    end  
endmodule
